class Solution {
    public int[] maximumCount(int[] nums, int[][] queries) {
        int n = nums.length;
        int[] primes = sieveOfEratosthenes(10 * 5 + 1);
        int[] prefixCount = new int[n];
        int[] count = new int[10 * 5 + 1];
        int distinctCount = 0;

        for (int i = 0; i < n; i++) {
            if (primes[nums[i]] == 1) {
                distinctCount++;
                count[nums[i]] = 1;
            }
            prefixCount[i] = distinctCount;
        }

        int[] result = new int[queries.length];
        for (int i = 0; i < queries.length; i++) {
            int idx = queries[i][0];
            int val = queries[i][1];

            if (primes[val] == 1 && count[val] == 0) {
                distinctCount++;
            }
            if (primes[val] == 1 && count[nums[idx]] == 1) {
                distinctCount--;
            }
            if (primes[nums[idx]] == 1 && count[nums[idx]] == 0) {
                distinctCount--;
            }
            if (primes[nums[idx]] == 1 && count[nums[idx]] == 1) {
                count[nums[idx]] = 0;
            }
            count[val] = primes[val];
            nums[idx] = val;

            int maxCount = 0;
            for (int k = 0; k < n - 1; k++) {
                int leftCount = prefixCount[k];
                int rightCount = distinctCount - leftCount;
                maxCount = Math.max(maxCount, leftCount + rightCount);
            }
            result[i] = maxCount;
        }
        return result;
    }

    private int[] sieveOfEratosthenes(int n) {
        int[] primes = new int[n + 1];
        for (int i = 0; i <= n; i++) {
            primes[i] = 1;
        }
        primes[0] = primes[1] = 0;
        for (int i = 2; i * i <= n; i++) {
            if (primes[i] == 1) {
                for (int j = i * i; j <= n; j += i) {
                    primes[j] = 0;
                }
            }
        }
        return primes;
    }
}
